ops.replace_with:
function triggerBuild() {
    const overlay = document.getElementById('trigger-build-overlay');
    overlay.classList.add('active');
    toggleFab(false);

    const workflowInput = document.getElementById('tb-workflow');

    // Load historical workflow list
    const suggestions = JSON.parse(localStorage.getItem('conduit_workflow_history') || '["build.yml", "deploy.yml", "speedster.yml"]');
    const dl = document.getElementById('workflow-suggestions');
    dl.innerHTML = suggestions.map(s => `<option value="${s}">`).join('');

    workflowInput.value = suggestions[0] || 'build.yml';
    document.getElementById('tb-branch').value = 'conduit-dev';

    // Sync extra fields on initial load
    syncWorkflowInputs(workflowInput.value);

    // Watch for changes to switch context
    workflowInput.oninput = (e) => syncWorkflowInputs(e.target.value);

    workflowInput.focus();
}

function syncWorkflowInputs(filename) {
    const extras = document.getElementById('tb-speedster-extras');
    const appLabelInput = document.getElementById('tb-app-label');
    const fileNameInput = document.getElementById('tb-file-name');

    // Show extra fields only if it looks like a speedster workflow
    const isSpeedster = filename.toLowerCase().includes('speedster');
    extras.style.display = isSpeedster ? 'flex' : 'none';

    // Load persisted inputs for this specific workflow
    const configMap = JSON.parse(localStorage.getItem('conduit_workflow_configs') || '{}');
    const saved = configMap[filename] || {};

    appLabelInput.value = saved.app_label || (isSpeedster ? 'Calculator Pro' : '');
    fileNameInput.value = saved.file_name || (isSpeedster ? 'calculator.dex' : '');
}

ops.find_block:
async function executeTriggerBuild() {
    const workflowFile = document.getElementById('tb-workflow').value.trim();
    const branch = document.getElementById('tb-branch').value.trim();
    if (!workflowFile || !branch) return showGlobalToast("Workflow and Branch are required", true);

    // Save to suggestions
    let suggestions = JSON.parse(localStorage.getItem('conduit_workflow_history') || '[]');
    suggestions = [workflowFile, ...suggestions.filter(s => s !== workflowFile)].slice(0, 10);
    localStorage.setItem('conduit_workflow_history', JSON.stringify(suggestions));

    closeTriggerModal();

