ops.replace_with:
function selectRepo(name) {
    document.getElementById('setting-repo-name').value = name;

    // Load known config for this repo if it exists
    const repoConfigs = JSON.parse(localStorage.getItem('conduit_repo_configs') || '{}');
    if (repoConfigs[name]) {
        const cfg = repoConfigs[name];
        if (cfg.projectType) {
            document.getElementById('setting-project-type').value = cfg.projectType;
            togglePreviewSettingsVisibility(cfg.projectType);
        }
        if (cfg.projectPath !== undefined) {
            document.getElementById('setting-project-path').value = cfg.projectPath;
        }
        showGlobalToast(`Config loaded for: ${name}`);
    }

    closeRepoSelector();
    showGlobalToast(`Repo set to: ${name}`);
}

